const Nr={className:"FogBlock",stage:"fragment",emit(e,t,f,o,r){o.fragment.helpers.set("nme_fog","fn nme_fogFactor(worldPos:vec3<f32>,cameraPos:vec3<f32>,fogParams:vec4<f32>)->f32{let dst=distance(worldPos,cameraPos);let mode=fogParams.x;let density=fogParams.y;let fstart=fogParams.z;let fend=fogParams.w;if(mode<1.5){return clamp(exp(-dst*density),0.0,1.0);}if(mode<2.5){let d=dst*density;return clamp(exp(-d*d),0.0,1.0);}return clamp((fend-dst)/(fend-fstart),0.0,1.0);}");const a=r.cast(r.resolve(e,"worldPosition",f,o),"vec3f").expr,s=r.resolve(e,"input",f,o),c=r.cast(r.resolve(e,"fogColor",f,o),"vec3f").expr,m="vec4f"===s.type?"vec4f":"vec3f",d=`mix(${c},${r.cast(s,"vec3f").expr},nme_fogFactor(${a},_NME_CAMERA_POS_,_NME_FOG_PARAMS_))`;return"vec4f"===m?{expr:`vec4<f32>(${d},(${s.expr}).w)`,type:"vec4f"}:{expr:d,type:"vec3f"};}};export{Nr as emitter};